import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { ALFComponent } from './alf/alf.component';
import { AUAComponent } from './aua/aua.component';
import { UFBComponent } from './ufb/ufb.component';
import { UPAComponent } from './upa/upa.component';
import { UPRComponent } from './upr/upr.component';



const routes: Routes = [{
  path: 'alf',
  component: ALFComponent
}, {
  path: 'aua',
  component: AUAComponent
}, {
  path: 'ufb',
  component: UFBComponent
}, {
  path: 'upa',
  component: UPAComponent
}, {
  path: 'upr',
  component: UPRComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class AUTRoutingModule { }
